string minWindow(string s, string t) {
    int m = s.length(), n = t.length();
    vector<int> charCount(256, 0); // 256 is the maximum possible character count in a string

    for (char c : s) {
        charCount[c]++;
    }

    int left = 0, right = 0, minLength = m, maxCount = INT_MIN;
    while (right < m) {
        int count = charCount[s[right]];
        if (count > maxCount) {
            minLength = right - left + 1;
            maxCount = count;
            left = right;
        }
        if (count <= t[0]) {
            break;
        }
        charCount[s[right]]--;
        right++;
    }

    string result = s.substr(left, minLength);
    return result;
}
